settings.stylesCss:
/** POWERED BY **/
#usercentrics-button .uc-powered-by-footer {display: none!important;}
#usercentrics-button #uc-consents-info-modal .uc-info-modal-sidebar .uc-powered-by  {
   display: none!important;}

/** Sidebar **/
label.uc-form-check-label {
    margin-left: 0px;
 }

/** FONTS **/
.usercentrics-button * {
	font-family: "Roboto",Arial,sans-serif!important;
	text-transform: none!important;
  }

#usercentrics-button h3 {
text-transform: uppercase!important;
font-family: "Archer A","Archer B","Roboto Condensed",serif!important;
	color: #393939!important;
}

.usercentrics-button.layout-1 .uc-header-title {
    font-weight: 400 !important;
    text-transform: uppercase!important;
    font-family: "Archer A","Archer B","Roboto Condensed",serif!important;
    color: #393939!important;
}

/* ------------------- BANNER ----------------------- */
.usercentrics-button #uc-banner-modal .uc-banner-wrapper {
    max-width: 1100px;
    margin: auto;
	margin-bottom: 20px;
}

span#uc-full-optin-description {
    line-height: 23px;
    color: #777;
font-weight: 300;
}

/* Buttons */
#usercentrics-button .uc-btn-new.uc-btn-accept {
    margin-bottom: 5px;
    line-height: 35px!important;
}

#usercentrics-button .uc-btn-new.uc-btn-more {
    margin-bottom: 5px;
    line-height: 35px!important;
}

/* ------------------- SIDE MODAL ----------------------- */
/*Position links über den ganzen Bildschirm ohne Rand*/
/*.uc-corner-modal-content.bl {
    top: 0 !important;
}

.usercentrics-button.uc-modal-1.uc-button-bl .uc-corner-modal .uc-corner-modal-content {
    left: 0 !important;
    bottom: 0 !important;*/
}

/* ------------------- Header ----------------------- */
/*Style für den Header (Datenschutz-Einstellungen)*/
.uc-card-header {
    height: 25vh !important;
    background-color: #fff !important;
}

/*Styles für alle Childern der Header Klasse*/
.uc-card-header * {
    color: #000 !important;
}

/*Styles um die Runden ecken zu entfernen*/

.usercentrics-button.layout-1 .uc-corner-modal .uc-corner-modal-content .uc-card-header {
    border-radius: 0px !important;
}

/*Close Button*/
svg#Capa_1>path {
    fill: #000 !important;
}

.usercentrics-button.layout-1 #uc-corner-modal.layout-1 .uc-corner-modal .uc-corner-modal-content .uc-card-header {
    padding: 30px 30px 0px 30px !important;
}
/*Sprachen*/
.uc-language-wrapper .svg-wrapper {
    margin-top: 5px;
}

/* ------------------- Body ----------------------- */
/*Styles für den Body (Einstellungen / Alles Auswählen)*/
.uc-card-body {
    height: 65vh !important;
    background-color: #fff !important;
}

.usercentrics-button.layout-1 .uc-corner-modal .uc-corner-modal-content .uc-card-body {
    padding: 0px 30px 0px 30px !important;
}

/*Style für Einstellung / Historie DIV*/
ul.uc-nav.uc-nav-tabs {
    background-color: #fff !important;
}

.usercentrics-button.layout-1 .uc-corner-modal .uc-corner-modal-content .uc-nav-tabs {
    font-size: 14px;
    margin-top: 24px!important;
}

/* Einstellungen und History AKTIV */
.usercentrics-button .uc-corner-modal .uc-corner-modal-content .uc-nav-tabs a.uc-active {
    color: #000 !important;
    padding: 0px !important;
    border-bottom-color: #000 !important;
    border-bottom-width: 1px !important;
}

/* Set Border für Aktive Einstellung bzw. Historie */
.usercentrics-button .uc-nav-tabs .uc-nav-link.uc-active {
    border-bottom-color: #000 !important;
    border-bottom-width: 1px !important;
}

.usercentrics-button .uc-nav-tabs .uc-nav-link.uc-active:hover {
    border-bottom-color: #000 !important;
    border-bottom-width: 1px !important;
}

/* Set Margin für Einstellungen */
li.uc-nav-item.width-50:first-child {
    margin-right: 20px !important;
    height: 5px !important;
}

/* Einstellungen und History Position*/
.usercentrics-button .uc-corner-modal .uc-corner-modal-content .uc-nav-tabs li {
    width: auto !important;
    min-width: auto !important;
    display: auto !important;
}

/* Einstellungen und History NOT AKTIV */
.usercentrics-button .uc-corner-modal .uc-corner-modal-content .uc-nav-tabs a {
    color: #000 !important;
    padding: 0px !important;
}

/* Remove Border */
#usercentrics-button.layout-1 #uc-corner-modal .uc-corner-modal-content .uc-tab-content {
    border: 0px !important;
}

.usercentrics-button .uc-nav-tabs .uc-nav-link {
    height: 26px !important;
}

.usercentrics-button .uc-corner-modal .uc-corner-modal-content h6 {
    margin-left: 20px;
    width: 100%;
}

/* Änderungen Absprache Frau Einhauser */
.usercentrics-button .uc-timeline .uc-history-timeline-dot.uc-green {
    background: #42b983!important;
}

.usercentrics-button .uc-timeline ul.uc-history-line::before {
    background: #42b983!important;
}

svg.uc-svg-id-circle- {
    display: none!important;
}

svg.uc-svg-history {
    display: none!important;
}

h6#uc-category-essential {
    letter-spacing: normal!important;
}

h6.uc-consent-title {
    letter-spacing: normal!important;
}

#usercentrics-button .uc-consent-title, .uc-embed .uc-consent-title {
    font-size: 15px!important;
}

.uc-header-subtitle-text {
    line-height: 21px!important;
    font-weight: 300!important;
}

#usercentrics-button .uc-consent-title, .uc-embed .uc-consent-title {
    margin-left: 15px!important;
}

#usercentrics-button input[type='checkbox'].uc-form-check-input.intermediate+label::before, .uc-embed input[type='checkbox'].uc-form-check-input.intermediate+label::before {
    background-color: #a0a0a0;
    border-color: #a0a0a0;
}

#usercentrics-button input[type='checkbox'].uc-form-check-input+label::before, .uc-embed input[type='checkbox'].uc-form-check-input+label::before {
    border: 2px solid #000;
}

.usercentrics-button .uc-inner-content .uc-row {
    margin-bottom: -4px!important;
}

/* ------------------- Footer ----------------------- */
/* Größe/Farbe des Footers */

.uc-card-footer {
    height: 10vh !important;
    background-color: #fff !important;
}

.usercentrics-button.layout-1 .uc-corner-modal .uc-corner-modal-content .uc-card-footer {
    padding: 0px 30px 30px 30px !important;
}

.uc-card-footer * {
   /* background-color: #fff !important;
	border: 1px solid #000!important;
    color: #000 !important;*/
    border-radius: 0px !important;
}

/* Runde Ecken des Footers entfernen */
.usercentrics-button.uc-modal-1.uc-button-bl .uc-corner-modal .uc-corner-modal-content .uc-card-footer {
    border-radius: 0px !important;
}



.usercentrics-button.layout-1 .uc-corner-modal .uc-corner-modal-content .uc-card-footer .uc-btn {
    border-radius: 5px!important;
}

/**------------------- MODALES FENSTER NACH KLICK ->(?) -------------------**/
#usercentrics-button #uc-consents-info-modal .uc-modal-header {
    background-color: #393939!important;
    border-bottom: 0!important;
    border-radius: 0 0 0 0!important;
    height: 65px!important;
}

#usercentrics-button #uc-consents-info-modal .uc-modal-header .uc-info-modal-search-bar input {
    background-color: #5c5c5c!important;
    border: 1px solid #5c5c5c!important;
  color: #000!important;
}

#usercentrics-button #uc-consents-info-modal .uc-info-modal-sidebar .uc-info-modal-sidebar-nav { background-color: #fff;}

#usercentrics-button #uc-consents-info-modal .uc-info-modal-sidebar .uc-powered-by  {
   display: none!important;}
#usercentrics-button #uc-consents-info-modal .uc-modal-footer .uc-save-settings-and-close-button {
    background-color: #393939!important;
    border-radius: 0 0 0 0!important;
    color: #fff!important;
    font-weight: 300!important;
  line-height: 200%!important;
}


#usercentrics-button #uc-consents-info-modal .uc-modal-header .uc-info-modal-search-bar input::placeholder {
    color: #fff!important;
}


/** BORDER RADIUS **/

.usercentrics-button.layout-1 .uc-corner-modal .uc-corner-modal-content .uc-card-header { border-top-left-radius: 0px!important; border-top-right-radius: 0px!important;}

#usercentrics-button #uc-consents-info-modal .uc-modal-header {
  border-bottom: 0;
  border-radius: 0 0 0 0!important;
  height: 65px;
}

.uc-border-radius-small {border-radius: 0;}
#usercentrics-button .uc-btn-new {border-radius: 0.14em;line-height: unset!important;font-size: 14px;}
